#include <bits/stdc++.h>
using namespace std;
int n,m;
int f[10004],a[10004],sum;
bool use[10004],flag;
void dfs(int x){
    if(sum>=m)
        return;
    if(x>n){
        sum+=flag;
        if(sum==m){
            for(int i=1;i<=n;i++)
                printf("%d ",a[i]);
            printf("\n");
        }
        return;
    }
    for(int i=1;i<=n;i++)
        if(!use[i] && (flag || i>=f[x])){
            bool last=flag;
            if(f[x]<i)
                flag=true;
            a[x]=i,use[i]=1,dfs(x+1),use[i]=0;
            flag=last;
        }
}
int main(){
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
        scanf("%d",&f[i]);
    dfs(1);
    return 0;
}
